#include <bits/stdc++.h>
using namespace std;
const int N=500005;
int n,a[N],b[N],maxid;
long long sum=1;
const long long mod=1e9+7;
int main()
{
	cin>>n;
	for(int i=1;i<=n;i++)
	{
		cin>>a[i];
	}
	for(int i=1;i<=n;i++) cin>>b[i];
    double maxx=0;
	for(int i=1;i<=n;i++)
	{
		if(a[i]==1)
		{
			sum+=b[i];
			continue;
		}
        double t=(double)(sum+b[i])/a[i];
		if(t>maxx)
        {
            maxx=t;
            maxid=i;
        }
	}
    if(maxx<sum) maxid=0;
    sum+=b[maxid];
    for(int i=1;i<=n;i++)
    {
        if(i==maxid) continue;
        sum=(sum*a[i])%mod;
    }
    cout<<sum;
	return 0;
}
